using System;

public class Employee {
    // Auto-Properties
    public string Name { get; set; }
    public double Salary { get; private set; } // Read-only from outside

    // Constructor
    public Employee(string name, double salary) {
        Name = name;
        Salary = salary;
    }

    public void GiveRaise(double amount) {
        Salary += amount;
        Console.WriteLine($"{Name} got a raise! New Salary: ${Salary}");
    }
}

class Program {
    static void Main() {
        Employee emp = new Employee("Alice", 50000);

        Console.WriteLine(emp.Name + " is hired.");

        // emp.Salary = 100000; // Error! Setter is private

        emp.GiveRaise(5000);

        Console.ReadKey();
    }
}
